    int maxProd = nums[0];
    int minProd = nums[0];
    int result = nums[0];

    for (int i = 1; i < numsSize; i++) {
        int num = nums[i];
        int temp1 = num * maxProd;
        int temp2 = num * minProd;

        int tempMax = num;
        if (temp1 > tempMax) tempMax = temp1;
        if (temp2 > tempMax) tempMax = temp2;

        int tempMin = num;
        if (temp1 < tempMin) tempMin = temp1;
        if (temp2 < tempMin) tempMin = temp2;

        maxProd = tempMax;
        minProd = tempMin;
        if (maxProd > result) result = maxProd;
    }

    return result;
}

