function maxAlternatingSum(nums) {
  let evenSum = 0; // max sum with even count (last operation was subtract)
  let oddSum = 0;  // max sum with odd count (last operation was add)

  for (const num of nums) {
    const newEven = Math.max(evenSum, oddSum - num);
    const newOdd = Math.max(oddSum, evenSum + num);
    evenSum = newEven;
    oddSum = newOdd;
  }

  return oddSum;
}

